static JSValueRef ct_bundle_native(JSContextRef ctx, JSObjectRef function, JSObjectRef thisObject, size_t argc, const JSValueRef argv[], JSValueRef *exception) {
    (void)function;
    (void)thisObject;
    if (argc < 2) {
        ct_throw_message(ctx, exception, "bundleNative(entrypoint, workingDirectory[, options]) requires two arguments");
        return JSValueMakeUndefined(ctx);
    }

    size_t entry_len = 0;
    size_t working_dir_len = 0;
    size_t options_len = 0;
    char *entry = ct_value_to_utf8_copy(ctx, argv[0], &entry_len);
    char *working_dir = ct_value_to_utf8_copy(ctx, argv[1], &working_dir_len);
    char *options = argc >= 3 ? ct_value_to_utf8_copy(ctx, argv[2], &options_len) : NULL;
    if (entry == NULL || working_dir == NULL || (argc >= 3 && options == NULL)) {
        free(entry);
        free(working_dir);
        free(options);
        ct_throw_message(ctx, exception, "Out of memory");
        return JSValueMakeUndefined(ctx);
    }

    size_t output_len = 0;
    char *error = NULL;
    pthread_mutex_lock(&ct_bundler_mutex);
    uint8_t *output = ct_bundle_entry_point_options(
        (const uint8_t *)entry,
        entry_len,
        (const uint8_t *)working_dir,
        working_dir_len,
        (const uint8_t *)options,
        options_len,
        &output_len,
        &error
    );
    pthread_mutex_unlock(&ct_bundler_mutex);
    free(entry);
    free(working_dir);
    free(options);
    if (output == NULL) {
        ct_throw_message(ctx, exception, error != NULL ? error : "JavaScript bundle failed");
        if (error != NULL) ct_bundle_string_free(error);
        return JSValueMakeUndefined(ctx);
    }
    JSValueRef result = ct_make_string_len(ctx, (const char *)output, output_len);
    ct_bundle_free(output, output_len);
    return result;
}

static JSValueRef ct_compile_function_native(JSContextRef ctx, JSObjectRef function, JSObjectRef thisObject, size_t argc, const JSValueRef argv[], JSValueRef *exception) {
    (void)function;
    (void)thisObject;
    if (argc < 2) {
        ct_throw_message(ctx, exception, "compileFunction(source, filename) requires two arguments");
        return JSValueMakeUndefined(ctx);
    }
    size_t source_len = 0;
    char *source_bytes = ct_value_to_utf8_copy(ctx, argv[0], &source_len);
    char *filename = ct_value_to_string_copy(ctx, argv[1]);
    if (source_bytes == NULL || filename == NULL) {
        free(source_bytes);
        free(filename);
        ct_throw_message(ctx, exception, "Out of memory compiling function");
        return JSValueMakeUndefined(ctx);
    }

    JSStringRef source = ct_js_string(source_bytes);
    JSStringRef source_url = ct_js_string(filename);
    JSValueRef eval_exception = NULL;
    JSValueRef result = JSEvaluateScript(ctx, source, NULL, source_url, 1, &eval_exception);
    JSStringRelease(source);
    JSStringRelease(source_url);
    free(source_bytes);
    free(filename);
    if (eval_exception != NULL) {
        if (exception != NULL) *exception = eval_exception;
        return JSValueMakeUndefined(ctx);
    }
    if (result == NULL || !JSValueIsObject(ctx, result) || !JSObjectIsFunction(ctx, (JSObjectRef)result)) {
        ct_throw_message(ctx, exception, "compileFunction source did not evaluate to a function");
        return JSValueMakeUndefined(ctx);
    }
    return result;
}

